draw(4/sin(pi/3)*dir(-30) -- (4/sin(pi/3)*dir(-30) + 6*dir(60)));
draw(rightanglemark(4/sin(pi/3)*dir(-30),4/sin(pi/3)*dir(-30) + 6*dir(60), (6/sin(pi/3)*dir(30)+4/sin(pi/3)*dir(-30))));
