draw(A--C);
draw(A--D);
[/asy] Now consider a circle of radius 4 inscribed inside a regular hexagon:
[asy]
size(150);
pair O, A, B, C, D, E, F, M;
O=(0,0);
A=(-4.619,0);
B=(-2.309,4);
C=(2.309,4);
D=(4.619,0);
E=(2.309,-4);
F=(-2.309,-4);
M=(A+B)/2;
draw(circle(O,4));
draw(A--B--C--D--E--F--A);
