  foo = foo--moo(t);
}

draw(foo,red);
label("$r = 4 \cos \theta$", (6.5,-1), red);

pair moo (real t) {
  real r = 8*sin(t);
  return (r*cos(t), r*sin(t));
}

path foo = moo(0);

for (t = 0; t <= pi + 0.1; t = t + 0.1) {
  foo = foo--moo(t);
}

